const item = $input.first().json;
const mensaje = item.messages?.[0];
if (!mensaje || mensaje.type !== 'text') return [];
const phoneNumberId = item.metadata?.phone_number_id ?? '';
const from = mensaje.from ?? '';
const messageText = mensaje.text?.body ?? '';
const timestamp = mensaje.timestamp ?? Math.floor(Date.now() / 1000);
if (!messageText.trim()) return [];
const codigoRML = 'RML-' + String(Math.floor(Math.random() * 10000)).padStart(4, '0');
return [{ json: { phoneNumberId, from, messageText, timestamp, codigoRML } }];
